VALUES
  ('social-worker-moex-05680', 'social-worker', 'social-worker-moex-105-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '《淮南子》：「夜行者掩目而前其手，涉水者解其馬載之舟。」下列選項何者最切合上文的意思？', '["一節見而百節知也", "以小見大，以近喻遠", "事有所宜，而有所不施", "所為之則同，其所以為之則異"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "bd0dfa1afbb5", "answer_pdf_sha1": "a508365c925c", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05681', 'social-worker', 'social-worker-moex-105-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列詩句「」中的花草樹木，何者象徵人格高潔？', '["青青陵上「柏」，磊磊澗中石。人生天地間，忽如遠行客", "傷彼「蕙蘭花」，含英揚光輝。過時而不采，將隨秋草萎", "方宅十餘畝，草屋八九間。「榆柳」蔭後簷，「桃李」羅堂前", "芳「菊」耀林開，青「松」冠巖列。懷此貞秀姿，卓為霜下傑"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "bd0dfa1afbb5", "answer_pdf_sha1": "a508365c925c", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05682', 'social-worker', 'social-worker-moex-105-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '白樸《梧桐雨》：「妾蒙主人恩寵無比，但恐春老花殘，主上恩移寵衰，使妾有龍陽險魚之悲，□□□□ 之怨，奈何？」依據文意推測，文中的□□□□，最適合填入的語詞應該是：', '["班姬題扇", "嫠婦夜哭", "牛郎織女", "煮豆燃萁"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "bd0dfa1afbb5", "answer_pdf_sha1": "a508365c925c", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05683', 'social-worker', 'social-worker-moex-105-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '父慈子孝，兄友弟恭，縱做到極處，俱是合當如此，著不得一毫感激的念頭。如施者任德，受者懷恩， 便是路人，便成市道矣。（《菜根譚》）下列選項何者最切合「市道」的意思？', '["人世的道理", "勢利的交易", "社會的風氣", "人間的道義"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "bd0dfa1afbb5", "answer_pdf_sha1": "a508365c925c", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05684', 'social-worker', 'social-worker-moex-105-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '《幽夢影》：「鶴，鳥中之伯夷也；雞，鳥中之伊尹也；鶯，鳥中之柳下惠也。」從歷史角度而言，作 者以「雞」比喻伊尹，可推斷他對伊尹的評價是：', '["雞腸鳥肚，胸襟狹隘", "呆若木雞，反應遲鈍", "割雞牛刀，大材小用", "雞鳴風雨，堅守崗位"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "bd0dfa1afbb5", "answer_pdf_sha1": "a508365c925c", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05685', 'social-worker', 'social-worker-moex-105-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「太史公曰：夫以汲、鄭之賢，有勢則賓客十倍，無勢則否，況眾人乎！下邽翟公有言，始翟公為廷尉， 賓客闐門；及廢，門外可設雀羅。翟公復為廷尉，賓客欲往，翟公乃大署其門曰：『一死一生，乃知交 情。一貧一富，乃知交態。一貴一賤，交情乃見。』汲、鄭亦云，悲夫！」（《史記．汲鄭列傳》）依 上文司馬遷以為：', '["有賢如汲鄭者，賓客十倍眾人", "有賢如翟公者，賓客闐門塞巷", "路遙知馬力，士窮見節義", "相見易得好，久住難為人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "bd0dfa1afbb5", "answer_pdf_sha1": "a508365c925c", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05686', 'social-worker', 'social-worker-moex-105-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '《史記．管晏列傳》謂晏嬰：「其在朝，君語及之，即危言；語不及之，即危行。國有道，即順命；無 道，即衡命。」下列敘述，何者與晏嬰的作為最相近？', '["言之者無罪，聞之者足以戒", "邦有道，危言危行，邦無道，危行言孫", "竭忠奉上，知無不盡，出入憂勤，形於顏色", "危邦不入，亂邦不居，天下有道則見，無道則隱"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "bd0dfa1afbb5", "answer_pdf_sha1": "a508365c925c", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05687', 'social-worker', 'social-worker-moex-105-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '與善人居，如入芝蘭之室，久而自芳也；與惡人居，如入鮑魚之肆，久而自臭也。墨翟悲於染絲，是之 謂矣。君子必慎交遊焉。孔子曰：「」，顏、閔之徒，何可世得！但優於我，便足貴之。（《顏氏家訓． 慕賢》）上文「」內最適宜填入的文句是：', '["無友不如己者", "四海之內皆兄弟也", "有朋自遠方來，不亦樂乎", "獨學而無友，則孤陋而寡聞"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "bd0dfa1afbb5", "answer_pdf_sha1": "a508365c925c", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05688', 'social-worker', 'social-worker-moex-105-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '名之與實，猶形之與影也。德藝周厚，則名必善焉；容色姝麗，則影必美焉。今不脩身而求令名於世者， 猶貌甚惡而責妍影於鏡也。上士忘名，中士立名，下士竊名。忘名者，體道合德，享鬼神之福祐，非所 以求名也；立名者，脩身慎行，懼榮觀之不顯，非所以讓名也；竊名者，厚貌深姦，干浮華之虛稱，非 所以得名也。（《顏氏家訓．名實》）根據上文，其欲彰顯的旨意為何？', '["吾性自足，不假外求", "求真求是，誠中形外", "捨本逐末，賢者所非", "術德兼修，精益求精"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "bd0dfa1afbb5", "answer_pdf_sha1": "a508365c925c", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05689', 'social-worker', 'social-worker-moex-105-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '楚人有涉江者，其劍自舟中墜於水，遽契其舟曰：「是吾劍之所從墜。」舟止，從其所契者入水求之。 舟已行矣，而劍不行，求劍若此，不亦惑乎？以此故法為其國，與此同，時已徙矣，而法不徙，以此為 治，豈不難哉？（《呂氏春秋．慎大覽．察今》）下列敘述何者最切合上文之意旨？', '["青松摧折，哀斷女蘿之心；丹節孤高，終守柏舟之誓", "王以名使括（趙括），若膠柱而鼓瑟耳。括徒能讀其父書傳，不知合變也", "（李林甫）尤忌文學之士，或陽與之善，啖以甘言而陰陷之。世謂李林甫「口有蜜，腹有劍」", "我即卑宮菲食，嘗膽臥薪，聚才智之精神，枕戈待旦，合方州之物力，破釜沈舟，尚恐無救於事"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "bd0dfa1afbb5", "answer_pdf_sha1": "a508365c925c", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
